import { Component, EventEmitter, Input, Output, OnChanges, SimpleChanges } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormBuilder, FormGroup, ReactiveFormsModule, Validators } from '@angular/forms';
import { Task } from '../../models/task.model';

@Component({
  selector: 'app-task-form',
  standalone: true,
  imports: [CommonModule, ReactiveFormsModule],
  templateUrl: './task-form.component.html',
  styleUrls: ['./task-form.component.css']
})
export class TaskFormComponent implements OnChanges {
  // 👇 Recibe la tarea a editar desde el tablero
  @Input() taskToEdit: Task | null = null; 

  @Output() taskAdded = new EventEmitter<Task>();
  @Output() taskUpdated = new EventEmitter<Task>(); // 👇 Nuevo evento de actualización
  @Output() cancelEdit = new EventEmitter<void>();  // 👇 Nuevo evento para cancelar

  taskForm: FormGroup;

  constructor(private fb: FormBuilder) {
    this.taskForm = this.fb.group({
      title: ['', Validators.required],
      description: [''],
      status: ['pending'],
      assignee: [''],
      startDate: [''],
      endDate: ['']
    });
  }

  // 👇 Se ejecuta cada vez que haces clic en "Editar" en una tarjeta
  ngOnChanges(changes: SimpleChanges) {
    if (changes['taskToEdit'] && this.taskToEdit) {
      this.taskForm.patchValue({
        title: this.taskToEdit.title,
        description: this.taskToEdit.description,
        status: this.taskToEdit.status,
        assignee: this.taskToEdit.assignee || '',
        startDate: this.taskToEdit.startDate || '',
        endDate: this.taskToEdit.endDate || ''
      });
    }
  }

  onSubmit() {
    if (this.taskForm.valid) {
      const taskData: Task = {
        title: this.taskForm.value.title,
        description: this.taskForm.value.description,
        status: this.taskForm.value.status,
        assignee: this.taskForm.value.assignee,
        startDate: this.taskForm.value.startDate,
        endDate: this.taskForm.value.endDate
      };

      if (this.taskToEdit && this.taskToEdit.id) {
        // MODO EDICIÓN
        taskData.id = this.taskToEdit.id;
        this.taskUpdated.emit(taskData);
      } else {
        // MODO CREACIÓN
        this.taskAdded.emit(taskData);
      }

      this.resetForm();
    }
  }

  onCancel() {
    this.resetForm();
    this.cancelEdit.emit();
  }

  private resetForm() {
    this.taskForm.reset({ status: 'pending', assignee: '', startDate: '', endDate: '' });
    this.taskToEdit = null;
  }
}
